impl Solution { pub fn maximize_the_profit(n: i32, offers: Vec<Vec<i32>>) -> i32 { let mut black_adj = vec![vec![]; n as usize]; for o in offers { black_adj[o[1] as usize].push((o[0], o[2])); } let mut black_dp = vec![0; n as usize + 1]; for i in 0..n as usize { black_dp[i+1] = black_dp[i]; for &(s, g) in &black_adj[i] { black_dp[i+1] = black_dp[i+1].max(black_dp[s as usize] + g); } } black_dp[n as usize] } }